def cmd_button(label, command, cls='mini'):
    return f'<button class="{html.escape(cls)}" onclick="copyCmd(\'{html.escape(command)}\')">{html.escape(label)}</button>'
def link_button(label, href):
    return f"<a class='buttonlink mini' href='{html.escape(href)}'>{html.escape(label)}</a>"
def toolbar(*items):
    return "<div class='section-tools'>" + ''.join(items) + "</div>"
